#include <iostream>

int main() {
    int n;
    std::cin >> n;
    int arr[1000];
    for (int i = 0; i < n; i++) {
        std::cin >> arr[i];
    }
    int target;
    std::cin >> target;
    int left = 0, right = n - 1, result = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) {
            result = mid;
            break;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    std::cout << result << std::endl;
    return 0;
}
